import fs from 'node:fs/promises'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { indent, joinBlocks, renderClass, renderInterface } from './template'

// ---------------------------------------------------------------------------
// Type mapping
// ---------------------------------------------------------------------------

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  BigInt: 'bigint',
  Float: 'number',
  Decimal: 'number',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/**
 * Converts a Prisma field type to its TypeScript equivalent.
 * Relation types fall through to their model name.
 */
function prismaTypeToTs(type: string, isList: boolean, isRequired: boolean): string {
  const base = SCALAR_TYPE_MAP[type] ?? type
  const listed = isList ? `${base}[]` : base
  return isRequired ? listed : `${listed} | null`
}

// ---------------------------------------------------------------------------
// Per-model interface generators
// ---------------------------------------------------------------------------

/** Renders the base model interface containing all scalar fields. */
function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const tsType = prismaTypeToTs(f.type, f.isList, f.isRequired)
      const optional = f.isRequired ? '' : '?'
      return `${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return renderInterface(model.name, fields)
}

/**
 * Renders a `<Model>WhereUnique` interface used for `findUnique`, `update`,
 * and `delete` lookups. Uses the model's ID or unique fields.
 */
function renderWhereUniqueInterface(model: DMMF.Model): string {
  const candidates = model.fields.filter((f) => f.isId || f.isUnique)
  const fields = (candidates.length > 0 ? candidates : model.fields.filter((f) => f.kind === 'scalar').slice(0, 1))
    .map((f) => `${f.name}: ${prismaTypeToTs(f.type, f.isList, true)}`)
    .join('\n')

  return renderInterface(`${model.name}WhereUnique`, fields)
}

/**
 * Renders a `Create<Model>Input` interface for the `create` method payload.
 * Required fields without defaults remain required; everything else is optional.
 */
function renderCreateInputInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' && !f.isReadOnly && !f.isGenerated)
    .map((f) => {
      const required = f.isRequired && !f.hasDefaultValue
      const tsType = prismaTypeToTs(f.type, f.isList, required)
      return `${f.name}${required ? '' : '?'}: ${tsType}`
    })
    .join('\n')

  return renderInterface(`Create${model.name}Input`, fields)
}

/**
 * Renders an `Update<Model>Input` interface for the `update` method payload.
 * All fields are optional to support partial updates.
 */
function renderUpdateInputInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' && !f.isReadOnly && !f.isGenerated && !f.isId)
    .map((f) => `${f.name}?: ${prismaTypeToTs(f.type, f.isList, false)}`)
    .join('\n')

  return renderInterface(`Update${model.name}Input`, fields)
}

// ---------------------------------------------------------------------------
// Per-model client class
// ---------------------------------------------------------------------------

/** Renders a typed REST client class for a single Prisma model. */
function renderModelClient(model: DMMF.Model): string {
  const m = model.name
  const urlPath = m.toLowerCase()

  const constructorBlock = [
    `readonly #baseUrl: string`,
    ``,
    `constructor(baseUrl: string) {`,
    `  this.#baseUrl = baseUrl.replace(/\\/$/, '')`,
    `}`,
  ].join('\n')

  const methods = [
    // findMany
    `async findMany(params?: { skip?: number; take?: number }): Promise<${m}[]> {`,
    `  const query = params ? \`?\${new URLSearchParams(params as Record<string, string>).toString()}\` : ''`,
    `  return this.#request('GET', \`/${urlPath}\${query}\`)`,
    `}`,
    ``,
    // findUnique
    `async findUnique(where: ${m}WhereUnique): Promise<${m} | null> {`,
    `  const id = Object.values(where)[0]`,
    `  return this.#request('GET', \`/${urlPath}/\${id}\`)`,
    `}`,
    ``,
    // create
    `async create(data: Create${m}Input): Promise<${m}> {`,
    `  return this.#request('POST', '/${urlPath}', data)`,
    `}`,
    ``,
    // update
    `async update(where: ${m}WhereUnique, data: Update${m}Input): Promise<${m}> {`,
    `  const id = Object.values(where)[0]`,
    `  return this.#request('PATCH', \`/${urlPath}/\${id}\`, data)`,
    `}`,
    ``,
    // delete
    `async delete(where: ${m}WhereUnique): Promise<${m}> {`,
    `  const id = Object.values(where)[0]`,
    `  return this.#request('DELETE', \`/${urlPath}/\${id}\`)`,
    `}`,
  ].join('\n')

  // Private fetch helper – defined last so it does not appear in public API docs.
  const requestHelper = [
    `async #request<T>(method: string, urlPath: string, body?: unknown): Promise<T> {`,
    `  const res = await fetch(\`\${this.#baseUrl}\${urlPath}\`, {`,
    `    method,`,
    `    headers: { 'Content-Type': 'application/json' },`,
    `    body: body !== undefined ? JSON.stringify(body) : undefined,`,
    `  })`,
    `  if (!res.ok) {`,
    `    throw new Error(\`REST API error \${res.status}: \${await res.text()}\`)`,
    `  }`,
    `  return res.json() as Promise<T>`,
    `}`,
  ].join('\n')

  const classBody = [constructorBlock, ``, methods, ``, requestHelper].join('\n')
  return renderClass(`${m}Client`, classBody)
}

// ---------------------------------------------------------------------------
// Full-file assembly
// ---------------------------------------------------------------------------

/**
 * Builds the complete `rest-client.ts` source from the DMMF document.
 * The output contains typed interfaces and a client class per model, plus a
 * top-level `RestClient` that aggregates all per-model clients.
 */
function buildRestClientSource(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models

  const header = [
    `// This file is auto-generated by @prisma/generator-rest-client. Do not edit.`,
    `/* eslint-disable */`,
    `// prettier-ignore`,
  ].join('\n')

  const modelSections = models.map((model) =>
    joinBlocks([
      renderModelInterface(model),
      renderWhereUniqueInterface(model),
      renderCreateInputInterface(model),
      renderUpdateInputInterface(model),
      renderModelClient(model),
    ]),
  )

  // Aggregate client that owns one typed sub-client per model.
  const aggregateProps = models
    .map((model) => {
      const prop = model.name.charAt(0).toLowerCase() + model.name.slice(1)
      return `readonly ${prop} = new ${model.name}Client(this.#baseUrl)`
    })
    .join('\n')

  const aggregateClassBody = [
    `readonly #baseUrl: string`,
    ``,
    `constructor(baseUrl: string) {`,
    `  this.#baseUrl = baseUrl`,
    `}`,
    ``,
    aggregateProps,
  ].join('\n')

  const aggregateClass = renderClass('RestClient', aggregateClassBody)

  return joinBlocks([header, ...modelSections, aggregateClass]) + '\n'
}

// ---------------------------------------------------------------------------
// Generator entry point
// ---------------------------------------------------------------------------

/**
 * Runs the REST client generator: writes a single `rest-client.ts` file to the
 * configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: `output` must be set in the generator block.')
  }

  await fs.mkdir(outputDir, { recursive: true })

  const source = buildRestClientSource(options.dmmf)
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), source, 'utf-8')
}

